  const browseResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "browse_category",
    args: {
      category: "sports",
      sortBy: "volume",
      limit: 5
    }
  });

  const events = Array.isArray(browseResult?.events) ? browseResult.events : [];
  if (events.length === 0) {
    return { error: "No sports events found on Polymarket." };
  }

  // 2. Take the top result by volume
  const topEvent = events[0];
  const { slug, title, volume, conditionId } = topEvent;

  // 3. Get detailed outcomes and individual odds for this top event
  // We use search_and_get_outcomes or get_event_outcomes to get the full list of candidate/team prices
  const outcomesResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "get_event_outcomes",
    args: {
      slug: slug,
      sortBy: "price"
    }
  });

  // 4. Also check market efficiency/vig to provide a complete "cross-reference" of the odds
  const efficiencyResult = await callMcpSkill({
    toolId: POLYMARKET_ID,
    toolName: "check_market_efficiency",
    args: {
      conditionId: conditionId
    }
  });

  return {
    topMarket: {
      title,
      slug,
      totalVolume: volume,
      url: topEvent.url
    },
    oddsBreakdown: outcomesResult.outcomes || [],
    analysis: {
      efficiency: efficiencyResult?.marketEfficiency,
      trueProbabilities: efficiencyResult?.trueProbabilitiesPercent,
      recommendation: efficiencyResult?.recommendation
    },
    note: "The top market was selected based on 24h trading volume."
  };
}

