  // The '2026 NBA Champion' maps to 'basketball_nba_championship_winner'
  const sportsbookOdds = await callMcpSkill({
    toolId: ODDS_API_ID,
    toolName: "get_outrights",
    args: {
      sport: "basketball_nba_championship_winner"
    }
  });

  // Find the specific NBA Championship event in the sportsbook data
  const nbaOutrightEvent = sportsbookOdds?.events?.find(e => 
    e.event.toLowerCase().includes("nba championship") || e.event.toLowerCase().includes("nba finals")
  );

  const bookieOutcomes = nbaOutrightEvent?.bookmakers?.[0]?.outcomes || [];

  // 5. Build Comparison Table
  const comparison = allOutcomes.slice(0, 10).map(polyTeam => {
    // Attempt to match names (e.g., "Oklahoma City Thunder" vs "Oklahoma City Thunder")
    const bookieMatch = bookieOutcomes.find(b => 
      b.name.toLowerCase().includes(polyTeam.name.toLowerCase()) || 
      polyTeam.name.toLowerCase().includes(b.name.toLowerCase())
    );

    const polyProb = polyTeam.price; // decimal probability
    const bookieProb = bookieMatch ? (1 / bookieMatch.price) : null;
    const discrepancy = (bookieProb && polyProb) ? (polyProb - bookieProb) : null;

    return {
      team: polyTeam.name,
      polymarketPrice: polyTeam.pricePercent,
      sportsbookPrice: bookieMatch ? `${(bookieProb * 100).toFixed(1)}%` : "N/A",
      discrepancyBps: discrepancy ? Math.round(discrepancy * 10000) : "N/A",
      isPolymarketHigher: discrepancy > 0
    };
  });

